using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Preserve EF Core 8 discriminator property name for existing documents.
            // Without this, EF Core 9 defaults to "$type" and existing queries on
            // c.Discriminator (including direct SQL) would break.
            entity.HasDiscriminator<string>("Discriminator");

            // Preserve EF Core 8 compound id format ("Product|123") so that
            // existing 500K documents remain accessible via FindAsync/point-reads.
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // Removed HasIndex — EF Core 9 Cosmos provider throws at startup.
        // Manage indexing policy via Azure Portal, Bicep, or Terraform instead.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

